<?php
namespace App\Domain\WorldMaps;use App\Models\Character;use App\Models\Region;use App\Models\World;use App\Models\WorldMap;
final class WorldMapReadService{
private $actions;private $images;private $projector;
public function __construct(WorldMapAreaActionResolver $actions,WorldMapImageService $images,WorldMapSvgProjector $projector){$this->actions=$actions;$this->images=$images;$this->projector=$projector;}
public function show(WorldMap $map,Character $character){$active=WorldMapAreaStatus::ACTIVE;$map=WorldMap::whereKey($map->id)->where('status',WorldMapStatus::ACTIVE)->with(['world','region.world','areas'=>function($q)use($active){$q->where('status',$active)->orderBy('z_index')->orderBy('sort_order')->orderBy('id')->with(['zone'=>function($z){$z->where('status','active')->with(['monsters'=>function($m){$m->where('monsters.status','active')->wherePivot('status','active')->with(['lootEntries'=>function($l){$l->where('status','active')->with('item');}]);}]);},'targetWorldMap','targetWorld','targetRegion']);}])->firstOrFail();$worldIds=$map->areas->pluck('target_world_id')->filter()->unique();$regionIds=$map->areas->pluck('target_region_id')->filter()->unique();$worldDefaults=$worldIds->isEmpty()?collect():WorldMap::whereIn('world_id',$worldIds)->where('status','active')->where('is_default',true)->get()->keyBy('world_id');$regionDefaults=$regionIds->isEmpty()?collect():WorldMap::whereIn('region_id',$regionIds)->where('status','active')->where('is_default',true)->get()->keyBy('region_id');$areas=$map->areas->map(function($area)use($character,$worldDefaults,$regionDefaults,$map){$action=$this->actions->resolve($area,$character,$worldDefaults,$regionDefaults);return['id'=>(int)$area->id,'code'=>$area->code,'name'=>$area->name,'polygon_points'=>$area->polygon_points,'svg_points'=>$this->projector->project($area->polygon_points,$map->original_width,$map->original_height),'z_index'=>(int)$area->z_index,'sort_order'=>(int)$area->sort_order,'style'=>['fill_color'=>$area->fill_color?:'#0d6efd','fill_opacity'=>$area->fill_opacity===null?0.25:(float)$area->fill_opacity,'stroke_color'=>$area->stroke_color?:'#ffffff','stroke_width'=>$area->stroke_width===null?2:(float)$area->stroke_width,'hover_fill_color'=>$area->hover_fill_color?:'#ffc107','hover_fill_opacity'=>$area->hover_fill_opacity===null?0.45:(float)$area->hover_fill_opacity],'action'=>$action];})->values()->all();return['map'=>['id'=>(int)$map->id,'name'=>$map->name,'description'=>(string)$map->description,'image_url'=>$this->images->url($map->image_disk,$map->image_path),'width'=>(int)$map->original_width,'height'=>(int)$map->original_height,'context'=>$map->world?['type'=>'world','name'=>$map->world->name]:['type'=>'region','name'=>$map->region->world->name.' › '.$map->region->name]],'areas'=>$areas,'selectors'=>$this->selectors()];}
public function showForWorldNavigation(WorldMap $map,Character $character,array $navigation){$presentation=$this->show($map,$character);$presentation['navigation']=$navigation;return$presentation;}
public function index(){return['selectors'=>$this->selectors()];}private function selectors(){$maps=WorldMap::where('status','active')->where('is_default',true)->get();$worldMaps=$maps->whereNotNull('world_id')->keyBy('world_id');$regionMaps=$maps->whereNotNull('region_id')->keyBy('region_id');$worlds=World::where('status','active')->with(['regions'=>function($q){$q->where('status','active')->orderBy('sort_order')->orderBy('name');}])->orderBy('sort_order')->orderBy('name')->get();return$worlds->map(function($world)use($worldMaps,$regionMaps){$worldMap=$worldMaps->get($world->id);return['name'=>$world->name,'map_url'=>$worldMap?route('world-maps.show',$worldMap):null,'regions'=>$world->regions->map(function($region)use($regionMaps){$map=$regionMaps->get($region->id);return['name'=>$region->name,'map_url'=>$map?route('world-maps.show',$map):null];})->filter(function($r){return$r['map_url']!==null;})->values()->all()];})->filter(function($w){return$w['map_url']!==null||!empty($w['regions']);})->values()->all();}}
